// packages/shared/src/types.ts
export interface TranscriptTurn {
  role: "user" | "assistant" | "tool";
  content: string;                    // 消息正文
  reasoning?: string;                 // 推理模型本轮的思考过程
  toolName?: string;
  toolInput?: string;
}

export interface AgentSession {
  id: string;
  prompt: string;
  reasoning?: string;                 // 会话级推理摘要（从 transcript 生成）
  response: string;
  transcript?: TranscriptTurn[];      // 逐轮对话记录
}
```

```typescript
// packages/backend/src/services/logService.ts
function transcriptToReasoning(turns: TranscriptTurn[]): string {
  // 格式：[User] 消息内容\n<think>\n推理文本\n</think>\n[Assistant] 回复内容
  return turns.map(t => {
    const thinkingBlock = t.reasoning && t.reasoning.trim()
      ? `\n<think>\n${t.reasoning.trim()}\n</think>`
      : '';
    return `${label}${thinkingBlock}\n${t.content}`;
  }).join('\n\n');
}
```

### 三、推理过程（reasoning）与交互记录（content）的区别

| 方面 | 推理过程（reasoning） | 交互记录（content） |
|---|---|---|
| **存储位置** | 1. TranscriptTurn.reasoning（每轮）<br>2. AgentSession.reasoning（会话级聚合） | TranscriptTurn.content（每轮） |
| **内容来源** | - DeepSeek-R1：`delta.reasoning_content`<br>- Claude：`thinking` content block<br>- 其他推理模型的思考过程 | - user/assistant：消息正文<br>- tool：工具执行结果摘要 |
| **界面显示** | - **每轮**：可折叠区块，标题"▶ 推理过程"<br>- **会话级**：折叠区块"💡 推理摘要" | - 每轮消息的主体内容<br>- 直接显示，无折叠 |
| **生成方式** | 由 Agent 在 `log_turn` 调用时传入 `reasoning` 参数 | 由 Agent 在 `log_turn` 调用时传入 `content` 参数 |
| **数据库字段** | `agent_sessions.reasoning`（文本）<br>`transcript.reasoning`（JSON 内） | `transcript.content`（JSON 内） |
| **必填性** | 可选，仅推理模型需要 | 必填（可为空字符串 "(pending)"） |

